module RAM (
    input clk, rst_n, write_en, read_en,
    input [2:0] write_addr, read_addr,
    input [5:0] write_data,
    output reg [5:0] read_data
);
    localparam WIDTH = 6;
    localparam DEPTH = 8;
    reg [DEPTH - 1 : 0] RAM [2**WIDTH-1:0];

    integer i;
    initial begin
        for(i = 0; i < 2**WIDTH; i = i+1) begin
            RAM[i] = 6'b000000;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            for(i = 0; i < 2**WIDTH; i = i+1) begin
                RAM[i] <= 6'b000000;
            end
        end
        else if(write_en) begin
            RAM[write_addr] <= write_data;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            read_data <= 6'b000000;
        end
        else if(read_en) begin
            read_data <= RAM[read_addr];
        end
        else begin
            read_data <= 6'b000000;
        end
    end
endmodule
